from typing import Protocol

class Saver(Protocol):
    def save(self) -> None:
        ...

class DiskSaver:
    def save(self) -> None:
        print('Saved')

def run_saver(s: Saver) -> None:
    s.save()

run_saver(DiskSaver())

practice_tasks.solution:
from typing import Protocol

class Notifier(Protocol):
    def send(self, message: str) -> None:
        ...

def notify_all(notifiers: list[Notifier], message: str) -> None:
    for notifier in notifiers:
        notifier.send(message)

code_walkthrough.code:
from typing import Protocol

class Drawable(Protocol):
    def draw(self) -> str:
        ...

class Circle:
    def draw(self) -> str:
        return 'O'

class Square:
    def draw(self) -> str:
        return '[]'

def render(shape: Drawable) -> None:
    print(shape.draw())

render(Circle())
render(Square())

