from typing import Protocol, runtime_checkable

@runtime_checkable
class Quacker(Protocol):
    def quack(self) -> None:
        ...

class Duck:
    def quack(self) -> None:
        print('Quack!')

donal = Duck()
print(isinstance(donal, Quacker))

challenge.solution:
from typing import Protocol

class Storage(Protocol):
    def save(self, filename: str, data: str) -> bool:
        ...

class LocalDiskStorage:
    def save(self, filename: str, data: str) -> bool:
        print(f'Saving {data} to {filename}')
        return True

def backup_data(storage: Storage) -> None:
    storage.save('backup.txt', 'important data')
